from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject = triples[0].subject
    sentence = f"{subject} is an airport that "
    for triple in triples:
        if triple.subject == subject:
            if triple.predicate == "cityServed":
                sentence += f"serves the city of {triple.object}, "
            elif triple.predicate == "location":
                sentence += f"located in {triple.object}, "
            elif triple.predicate == "operatingOrganisation":
                sentence += f"operated by {triple.object}, "
            elif triple.predicate == "elevationAboveTheSeaLevel":
                sentence += f"with an elevation of {triple.object} meters, "
            elif triple.predicate == "runwayLength":
                sentence += f"with a runway length of {triple.object} meters, "
            elif triple.predicate == "runwayName":
                sentence += f"with a runway named {triple.object}, "
            elif triple.predicate == "country":
                sentence += f"located in the country of {triple.object}, "
            elif triple.predicate == "isPartOf":
                sentence += f"part of {triple.object}, "
            elif triple.predicate == "mayor":
                sentence += f"where the mayor is {triple.object}, "
        else:
            if triple.predicate == "mayor":
                sentence += f"where the mayor of {triple.subject} is {triple.object}, "
            elif triple.predicate == "country":
                sentence += f"{triple.subject} is located in the country of {triple.object}, "
    return sentence.strip()[:-1] + "."

